t.script:
(() => {
    const presetButtons = document.querySelectorAll(".o_securec_payload_preset");
    const payloadEl = document.getElementById("securec-attack-payload");
    const runBtn = document.getElementById("securec-run-attack");
    const clearBtn = document.getElementById("securec-clear-attack");
    const resultEl = document.getElementById("securec-attack-result");
    const secLogsEl = document.getElementById("securec-security-logs");
    const auditLogsEl = document.getElementById("securec-audit-logs");

    const rpc = async (url, params) => {
        const response = await fetch(url, {
            method: "POST",
            headers: {"Content-Type": "application/json"},
            credentials: "same-origin",
            body: JSON.stringify({
                jsonrpc: "2.0",
                method: "call",
                params: params || {},
                id: Date.now(),
            }),
        });
        const data = await response.json();
        if (data.error) {
            const message = data.error.data && data.error.data.message ? data.error.data.message : "RPC failed";
            throw new Error(message);
        }
        return data.result;
    };

    const esc = (value) => String(value || "").replaceAll("&", "&amp;").replaceAll("<", "&lt;").replaceAll(">", "&gt;");

    const renderRows = (rows, keys) => {
        if (!rows || !rows.length) {
            return '<div class="text-muted">No records yet.</div>';
        }
        return rows.map((row) => {
            const cells = keys.map((k) => `<div><b>${k}</b>: ${esc(row[k])}</div>`).join("");
            return `<div class="border rounded p-2 mb-2">${cells}</div>`;
        }).join("");
    };

    const renderResult = (analysis) => {
        if (!analysis) {
            resultEl.innerHTML = '<div class="text-muted">No result.</div>';
            return;
        }
        const risk = Number(analysis.risk_score || 0);
        const decision = String(analysis.decision || "allow").toUpperCase();
        const klass = decision === "BLOCK" ? "danger" : (decision === "WARN" || decision === "SANITIZE" ? "warning" : "success");
        const patterns = (analysis.detected_patterns || []).map(esc).join("<br/>") || "none";
        const explanation = esc(analysis.explanation || "");
        resultEl.innerHTML = `
            <div class="mb-2"><span class="badge text-bg-${klass}">${decision}</span></div>
            <div class="mb-1"><b>Risk Score:</b> ${(risk * 100).toFixed(1)}%</div>
            <div class="mb-1"><b>Request ID:</b> ${esc(analysis.request_id || "n/a")}</div>
            <div class="mb-1"><b>Explanation:</b> ${explanation}</div>
            <div><b>Detected Patterns:</b><br/>${patterns}</div>
        `;
    };

    presetButtons.forEach((btn) => {
        btn.addEventListener("click", () => {
            payloadEl.value = btn.dataset.payload || "";
        });
    });

    clearBtn.addEventListener("click", () => {
        payloadEl.value = "";
        resultEl.innerHTML = '<div class="text-muted">Run a payload to see WAF decision details.</div>';
    });

    runBtn.addEventListener("click", async () => {
        const payload = payloadEl.value.trim();
        if (!payload) {
            resultEl.innerHTML = '<div class="text-danger">Please provide a payload first.</div>';
            return;
        }
        runBtn.disabled = true;
        runBtn.textContent = "Scanning...";
        try {
            const data = await rpc("/securec/attack_lab/run", {input_text: payload, module: "AttackLab"});
            if (data.error) {
                throw new Error(data.error);
            }
            renderResult(data.analysis);
            secLogsEl.innerHTML = renderRows(data.security_logs, ["timestamp", "module", "risk_score", "decision", "detected_patterns"]);
            auditLogsEl.innerHTML = renderRows(data.audit_logs, ["timestamp", "application", "event_type", "status", "login", "details"]);
        } catch (err) {
            resultEl.innerHTML = `<div class="text-danger">${esc(err.message || err)}</div>`;
        } finally {
            runBtn.disabled = false;
            runBtn.textContent = "Run Scan";
        }
    });
})();
